const std = @import("std");

fn parseInput(input: []const u8) !(?struct { row: usize, col: usize }) {
    // Input format example:
    // "To continue, please consult the code grid in the manual.  Enter the code at row 2978, column 3083."
    // We want to extract row=2978, col=3083
    var it = std.mem.tokenize(input, " ,.\n");
    var row: ?usize = null;
    var col: ?usize = null;

    while (it.next()) |token| {
        if (std.mem.eql(u8, token, "row")) {
            if (it.next()) |row_str| {
                const parsed = std.fmt.parseInt(usize, row_str, 10);
                if (parsed) |r| {
                    row = r;
                } else {
                    return error.InvalidInput;
                }
            } else {
                return error.InvalidInput;
            }
        } else if (std.mem.eql(u8, token, "column")) {
            if (it.next()) |col_str| {
                const parsed = std.fmt.parseInt(usize, col_str, 10);
                if (parsed) |c| {
                    col = c;
                } else {
                    return error.InvalidInput;
                }
            } else {
                return error.InvalidInput;
            }
        }
    }
    if (row and col) |r, c| {
        return .{ .row = r, .col = c };
    } else {
        return null;
    }
}

fn codeIndex(row: usize, col: usize) usize {
    // The codes are filled diagonally:
    // The order of codes is:
    // 1: (1,1)
    // 2: (2,1)
    // 3: (1,2)
    // 4: (3,1)
    // 5: (2,2)
    // 6: (1,3)
    // 7: (4,1)
    // 8: (3,2)
    // 9: (2,3)
    // 10: (1,4)
    //
    // The diagonal number d = row + col - 1
    // The number of codes before diagonal d is sum_{k=1}^{d-1} k = (d-1)*d/2
    // The position in diagonal d is (d - row + 1)
    // So the index = codes before diagonal + position in diagonal
    const d = row + col - 1;
    return (d * (d - 1)) / 2 + col;
}

fn codeAtIndex(index: usize) u64 {
    // First code is 20151125
    // next code = (previous * 252533) % 33554393
    var code: u64 = 20151125;
    const multiplier: u64 = 252533;
    const modulo: u64 = 33554393;

    var i: usize = 1;
    while (i < index) : (i += 1) {
        code = (code * multiplier) % modulo;
    }
    return code;
}

pub fn main() !void {
    const stdout = std.io.getStdOut().writer();
    const allocator = std.heap.page_allocator;

    const file = try std.fs.cwd().openFile("input.txt", .{});
    defer file.close();

    const file_contents = try file.readToEndAlloc(allocator, 1024);
    defer allocator.free(file_contents);

    const parsed = try parseInput(file_contents) catch {
        std.debug.print("Failed to parse input\n", .{});
        return;
    };

    if (parsed) |pos| {
        const idx = codeIndex(pos.row, pos.col);
        const code = codeAtIndex(idx);
        try stdout.print("{}\n", .{code});
    } else {
        std.debug.print("Could not find row and column in input\n", .{});
    }
}
