    std::ofstream directionFile(path);
    directionFile << direction;
    directionFile.close();
}

// Function to write value to GPIO (0 or 1)
void gpioWrite(int pin, int value) {
    std::string path = "/sys/class/gpio/gpio" + std::to_string(pin) + "/value";
    std::ofstream valueFile(path);
    valueFile << value;
    valueFile.close();
}

