    {
        private const string Dir = @"C:\C#\files\";
        private const string Path = Dir + "Students.dat";

        // Save a list of students to the binary file
        public static void SaveStudents(List<Student> students)
        {
            if (!Directory.Exists(Dir))
            {
                Directory.CreateDirectory(Dir);
            }

            using BinaryWriter binaryOut = new(
                new FileStream(Path, FileMode.Create, FileAccess.Write));

            foreach (Student student in students)
            {
                binaryOut.Write(student.StudentID);
                binaryOut.Write(student.Name);
                binaryOut.Write(student.GPA);
            }
        }

        // Read all students from the binary file
        public static List<Student> GetStudents()
        {
            List<Student> students = new();

            if (!Directory.Exists(Dir))
            {
                Directory.CreateDirectory(Dir);
            }

            if (!File.Exists(Path))
            {
                return students; // Return empty list if file does not exist
            }

            using BinaryReader binaryIn = new(
                new FileStream(Path, FileMode.Open, FileAccess.Read));

            while (binaryIn.BaseStream.Position < binaryIn.BaseStream.Length)
            {
                Student student = new()
                {
                    StudentID = binaryIn.ReadInt32(),
                    Name = binaryIn.ReadString(),
                    GPA = binaryIn.ReadDecimal()
                };
                students.Add(student);
            }

            return students;
        }
    }
}
