Certainly! Below is an example of how to use the `AudioCapture` class (which is part of the Audio Capture plugin) directly in your GameMode in Unreal Engine 5 using C++.

**Note:**  
- `AudioCapture` is a low-level class that provides audio input capture functionality.  
- You need to enable the **Audio Capture** plugin in your project.  
- `AudioCapture` is not a component, so you instantiate and manage it manually.  
- This example shows how to start capturing audio and receive audio data via a delegate.

---

### Step 1: Enable Audio Capture Plugin

1. Open your project in Unreal Editor.
2. Go to **Edit > Plugins**.
3. Search for **Audio Capture** and enable it.
4. Restart the editor if prompted.

---

### Step 2: Setup Your GameMode Header

Create or modify your GameMode header file, e.g., `MyGameMode.h`:

```cpp
#pragma once

#include "CoreMinimal.h"
#include "GameFramework/GameModeBase.h"
#include "AudioCapture.h"  // Include AudioCapture header
#include "MyGameMode.generated.h"

UCLASS()
class YOURPROJECT_API AMyGameMode : public AGameModeBase
{
    GENERATED_BODY()

public:
    AMyGameMode();

    virtual void BeginPlay() override;
    virtual void EndPlay(const EEndPlayReason::Type EndPlayReason) override;

private:
    // Pointer to AudioCapture instance
    TUniquePtr<Audio::FAudioCapture> AudioCapture;

    // Delegate function to receive audio data
    void OnAudioCapture(const float* AudioData, int32 NumFrames, int32 NumChannels, double StreamTime, bool bOverFlow);
};
```

---

### Step 3: Implement Your GameMode Source

In `MyGameMode.cpp`:

```cpp
#include "MyGameMode.h"
#include "AudioCapture.h"
#include "AudioDevice.h"
#include "Misc/ScopeLock.h"

AMyGameMode::AMyGameMode()
{
    // Create the AudioCapture instance
    AudioCapture = MakeUnique<Audio::FAudioCapture>();
}

void AMyGameMode::BeginPlay()
{
    Super::BeginPlay();

    if (AudioCapture.IsValid())
    {
        // Initialize the audio capture device (default device)
        if (AudioCapture->OpenDefaultDevice())
        {
            // Bind the delegate to receive audio data
            AudioCapture->OnAudioCaptureNative.AddRaw(this, &AMyGameMode::OnAudioCapture);

            // Start capturing audio
            AudioCapture->StartStream();

            UE_LOG(LogTemp, Log, TEXT("Audio capture started."));
        }
        else
        {
            UE_LOG(LogTemp, Warning, TEXT("Failed to open default audio capture device."));
        }
    }
}

void AMyGameMode::EndPlay(const EEndPlayReason::Type EndPlayReason)
{
    if (AudioCapture.IsValid())
    {
        AudioCapture->StopStream();
        AudioCapture->CloseDevice();
        AudioCapture->OnAudioCaptureNative.RemoveAll(this);

        UE_LOG(LogTemp, Log, TEXT("Audio capture stopped."));
    }

    Super::EndPlay(EndPlayReason);
}

void AMyGameMode::OnAudioCapture(const float* AudioData, int32 NumFrames, int32 NumChannels, double StreamTime, bool bOverFlow)
{
    // AudioData is a pointer to the captured audio samples (float PCM data)
    // NumFrames = number of audio frames captured
    // NumChannels = number of audio channels (e.g., 1 for mono, 2 for stereo)
    // StreamTime = current stream time in seconds
    // bOverFlow = true if audio buffer overflowed

    // Example: Log the first sample of the first channel
    if (AudioData && NumFrames > 0 && NumChannels > 0)
    {
        float FirstSample = AudioData[0];
        UE_LOG(LogTemp, Verbose, TEXT("Captured audio sample: %f, Frames: %d, Channels: %d, Overflow: %s"), FirstSample, NumFrames, NumChannels, bOverFlow ? TEXT("true") : TEXT("false"));
    }
}
```

---

### Explanation

- We create an `FAudioCapture` instance in the constructor.
- In `BeginPlay()`, we open the default audio capture device and start streaming.
- We bind `OnAudioCapture` to the `OnAudioCaptureNative` delegate to receive audio data callbacks.
- In `OnAudioCapture()`, you get raw PCM audio data as floats.
- In `EndPlay()`, we stop and close the audio capture device and unbind the delegate.

---

