      if (err) {
        reject(err);
      } else {
        resolve(result);
      }
    });
  });
}

/**
 * パスワード変更リクエストのバリデーションを行う
 */
function validatePasswordChangeRequest(
  currentPassword: string,
  newPassword: string,
  newPasswordConfirmation: string
) {
  if (newPassword === currentPassword) {
    throw new Error(
      "新しいパスワードは現在のパスワードと違うものを入力してください"
    );
  }
  if (newPassword !== newPasswordConfirmation) {
    throw new Error("新しいパスワードが一致しません");
  }
}

const updateUserPasswordRoute: FastifyPluginAsyncTypeProvider = async (fastify) => {
  fastify.setSerializerCompiler(serializerCompiler);
  fastify.setValidatorCompiler(validatorCompiler);

  fastify.patch(
    "/",
    {
      schema: {
        body: updateUserPasswordSchema,
      },
    },
    async (request, reply) => {
      // 認証済みユーザーの取得
      const authedUser = validateAuthUser(request.user);

      // ユーザー情報の取得
      const userRecord = await prisma.users.findUnique({
        where: { id: authedUser.id },
      });
      if (!userRecord) {
        throw fastify.httpErrors.notFound("ユーザー情報がありません");
      }

      // 現在のパスワードが正しいか検証
      let isPasswordValid: boolean;
      try {
        isPasswordValid = await comparePassword(
          request.body.password,
          userRecord.password
        );
      } catch (error) {
        throw fastify.httpErrors.internalServerError();
      }

      if (!isPasswordValid) {
        throw fastify.httpErrors.badRequest("現在のパスワードが異なります");
      }

      // 新しいパスワードのバリデーション
      try {
        validatePasswordChangeRequest(
          request.body.password,
          request.body.new_password,
          request.body.new_password_confirmation
        );
      } catch (error) {
        throw fastify.httpErrors.badRequest((error as Error).message);
      }

      // パスワード変更処理
      await changePassword({
        user_id: authedUser.id,
        password: request.body.new_password,
      });

      reply.send("OK");
    }
  );
};

export default updateUserPasswordRoute;
```

