Certainly! Below is an example of a Python application using the `Textual` library by Textualize. It displays a list of files, each with a "Delete" button next to it. When you press the "Delete" button, the corresponding file entry is removed from the list.

This example demonstrates how to have buttons associated with each item (like a "button within button" concept, or more precisely, a button per list item).

```python
from textual.app import App, ComposeResult
from textual.widgets import Button, Static, ScrollView
from textual.containers import Vertical, Horizontal
from textual.message import Message
from textual.reactive import reactive

class FileItem(Horizontal):
    """A widget representing a file with a delete button."""

    class DeleteClicked(Message):
        """Message sent when the delete button is clicked."""
        def __init__(self, sender: "FileItem", filename: str) -> None:
            self.filename = filename
            super().__init__(sender)

    def __init__(self, filename: str) -> None:
        super().__init__()
        self.filename = filename

    def compose(self) -> ComposeResult:
        yield Static(self.filename, expand=True)
        yield Button("Delete", id="delete-btn")

    def on_button_pressed(self, event: Button.Pressed) -> None:
        if event.button.id == "delete-btn":
            self.post_message(self.DeleteClicked(self, self.filename))


class FileListApp(App):
    CSS = """
    Screen {
        align: center middle;
    }
    #files {
        width: 60%;
        height: 80%;
        border: round white;
        padding: 1 2;
    }
    FileItem {
        padding: 1 0;
        border: none;
    }
    Button {
        background: red;
        color: white;
    }
    """

    files = reactive([
        "document.txt",
        "image.png",
        "notes.md",
        "script.py",
        "data.csv",
    ])

    def compose(self) -> ComposeResult:
        yield Static("File List (Press Delete to remove a file)", id="header")
        with ScrollView(id="files"):
            with Vertical():
                for filename in self.files:
                    yield FileItem(filename)

    def on_file_item_delete_clicked(self, message: FileItem.DeleteClicked) -> None:
        filename = message.filename
        if filename in self.files:
            self.files.remove(filename)
            # Refresh the file list display
            files_container = self.query_one("#files > Vertical")
            files_container.clear()
            for f in self.files:
                files_container.mount(FileItem(f))


if __name__ == "__main__":
    FileListApp().run()
```

### How it works:
- `FileItem` is a widget representing a single file entry with a label and a "Delete" button.
- When the "Delete" button is pressed, `FileItem` sends a `DeleteClicked` message with the filename.
- The main app listens for these messages and updates the list of files accordingly.
- The file list is displayed inside a scrollable container.

### To run this code:
1. Install textual if you haven't already:
   ```
   pip install textual
   ```
2. Save the code to a file, e.g., `file_list_app.py`.
3. Run it:
   ```
   python file_list_app.py
   ```

You will see a list of files with delete buttons. Pressing a delete button removes that file from the list.

