        return ok;
    }

    // Check for octal: starts with 0 and length > 1 (to avoid single zero)
    if (s.startsWith('0') && s.length() > 1 && s[1] != 'x' && s[1] != 'b') {
        outNumber = s.toInt(&ok, 8);
        return ok;
    }

    // Otherwise, try decimal or float
    // First try integer decimal
    outNumber = s.toInt(&ok, 10);
