// Function to load and modify SVG content
function loadAndModifySVG(url, callback) {
  fetch(url)
    .then(response => {
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      return response.text();
    })
    .then(svgText => {
      // Use a regex to find the <svg ...> start tag
      const svgTagMatch = svgText.match(/<svg[^>]*>/);
      if (!svgTagMatch) {
        throw new Error('SVG tag not found');
      }

      let svgTag = svgTagMatch[0];

      // Remove width and height attributes
      svgTag = svgTag.replace(/\s(width|height)="[^"]*"/g, '');

      // Replace version attribute value to 1.1 (or add if missing)
      if (svgTag.includes('version=')) {
        svgTag = svgTag.replace(/version="[^"]*"/, 'version="1.1"');
      } else {
        svgTag = svgTag.replace('<svg', '<svg version="1.1"');
      }

      // Add onload attribute (if not already present)
      if (!svgTag.includes('onload=')) {
        svgTag = svgTag.replace('<svg', '<svg onload="createAlarmSVGLinks(\'../wtrtrmt_alarms.htm\')"');
