    for i in range(2, int(n**0.5)+1):
        if n % i == 0:
            return False
    return True

def generate_primes(n):
    primes = []
    num = 2
    while len(primes) < n:
        if is_prime(num):
            primes.append(num)
        num += 1
    return primes

class TodoApp:
    def __init__(self):
        self.todos = []  # list of (task:str, completed:bool)

    def add(self, task):
        self.todos.append((task, False))
        print(f'Added todo: "{task}"')

    def complete(self, index):
        if 0 <= index < len(self.todos):
            task, _ = self.todos[index]
            self.todos[index] = (task, True)
            print(f'Marked todo #{index+1} as completed.')
        else:
            print("Invalid todo number.")

    def list_todos(self):
        incomplete = [(i, t) for i, (t, c) in enumerate(self.todos) if not c]
        complete = [(i, t) for i, (t, c) in enumerate(self.todos) if c]

        primes = generate_primes(len(complete))

        print("\nCurrent Todos:")
        # Print incomplete todos with natural numbers starting from 1
        for idx, (i, task) in enumerate(incomplete, start=1):
            print(f"{idx}. [ ] {task}")

        # Print completed todos with prime numbers
        for prime, (i, task) in zip(primes, complete):
            print(f"{prime}. [x] {task}")
        print()

def main():
    app = TodoApp()

    while True:
        print("Options:")
        print("1. Add todo")
        print("2. Complete todo")
        print("3. List todos")
        print("4. Exit")
        choice = input("Choose an option: ").strip()

        if choice == '1':
            task = input("Enter todo task: ").strip()
            if task:
                app.add(task)
            else:
                print("Task cannot be empty.")
        elif choice == '2':
            app.list_todos()
            try:
                num = int(input("Enter the number of the todo to mark as completed: ").strip())
            except ValueError:
                print("Please enter a valid number.")
                continue

            # We need to map the input number to the index in self.todos
            # Since incomplete todos are numbered 1..n, and completed todos are primes,
            # only incomplete todos can be marked completed.
            # So if the number is a natural number (not prime), it corresponds to incomplete todo.

            # Get incomplete todos indices
            incomplete_indices = [i for i, (_, c) in enumerate(app.todos) if not c]

            if num in range(1, len(incomplete_indices)+1):
                todo_index = incomplete_indices[num-1]
                app.complete(todo_index)
            else:
                print("Invalid todo number or todo already completed.")
        elif choice == '3':
            app.list_todos()
        elif choice == '4':
            print("Goodbye!")
            break
        else:
            print("Invalid option. Please choose 1-4.")

if __name__ == "__main__":
    main()
```

### How it works:
- When you list todos, incomplete todos are numbered 1, 2, 3, ... and completed todos are numbered with prime numbers 2, 3, 5, 7, ...
- You can only mark incomplete todos as completed by entering their natural number.
- The app runs in a loop until you choose to exit.

