podTemplateSpec: {
    metadata: v1.ObjectMeta & {
        labels: metadata.labels
    }
    spec: v1.PodSpec & {
        containers: [...v1.Container]
        volumes?: [...v1.Volume]
    }
}

// Deployment spec
deploymentSpec: v1.DeploymentSpec & {
    replicas: int | *1
    selector: v1.LabelSelector & {
        matchLabels: metadata.labels
    }
    template: podTemplateSpec
}

