homeAssistantContainer: containerSpec & {
    name:  "home-assistant"
    image: "homeassistant/home-assistant:stable"
    ports: [8123]
    volumeMounts: [{
        name:      "config"
        mountPath: "/config"
    }]
}

// Define nginx container
nginxContainer: containerSpec & {
    name:  "nginx"
    image: "nginx:latest"
    ports: [80]
    volumeMounts: [{
        name:      "nginx-conf"
        mountPath: "/etc/nginx/conf.d"
    }]
}

