    apiVersion: "apps/v1"
    kind:       "Deployment"
    metadata: metadata & {
        name:   "home-assistant-nginx"
        labels: { app: "home-assistant-nginx" }
    }
    spec: deploymentSpec & {
        replicas: 1
        template: podTemplateSpec & {
