Certainly! Below is a perfect TypeScript implementation of a utility function that wraps any synchronous function in a try/catch block and returns a `Result` type indicating success or failure.

```typescript
// Define the Result type
type Result<T, E = unknown> = 
  | { success: true; value: T }
  | { success: false; error: E };

// The wrapper function
function tryCatch<T, Args extends any[], E = unknown>(
  fn: (...args: Args) => T,
  ...args: Args
): Result<T, E> {
  try {
    const value = fn(...args);
    return { success: true, value };
  } catch (error) {
    return { success: false, error: error as E };
  }
}
```

### Usage example:

```typescript
function mightThrow(n: number): number {
  if (n < 0) throw new Error("Negative number!");
  return n * 2;
}

const result1 = tryCatch(mightThrow, 5);
if (result1.success) {
  console.log("Success:", result1.value);
} else {
  console.error("Error:", result1.error);
}

const result2 = tryCatch(mightThrow, -1);
if (!result2.success) {
  console.error("Caught error:", result2.error);
}
```

