class CleaningState(State):
    def run(self, context):
        print("Cleaning data...")
        df = context['df']
        # Example cleaning: ensure authors are lists, years are int, citations are int
        df['authors'] = df['authors'].apply(lambda x: x if isinstance(x, list) else [x])
        df['year'] = df['year'].astype(int)
        df['citations'] = df['citations'].astype(int)
        context['df'] = df
        return AnalyzingState()

class AnalyzingState(State):
    def run(self, context):
        print("Analyzing bibliometric data...")
        df = context['df']

        # 1. Publication count per author
        author_pub_counts = defaultdict(int)
        for authors in df['authors']:
            for author in authors:
                author_pub_counts[author] += 1

        # 2. Citation count per author (sum citations of their papers)
        author_citations = defaultdict(int)
        for _, row in df.iterrows():
            for author in row['authors']:
                author_citations[author] += row['citations']

