use Drupal\taxonomy\Entity\Term;

/**
 * Load the taxonomy term ID by name.
 *
 * @param string $term_name
 *   The taxonomy term name.
 * @param string $vocabulary
 *   The vocabulary machine name.
 *
 * @return int|null
 *   The term ID or NULL if not found.
 */
function get_term_id_by_name(string $term_name, string $vocabulary): ?int {
  $terms = \Drupal::entityTypeManager()
    ->getStorage('taxonomy_term')
    ->loadByProperties([
      'name' => $term_name,
      'vid' => $vocabulary,
    ]);
  if ($terms) {
    $term = reset($terms);
    return $term->id();
  }
  return NULL;
}
```

---

## Step 2: Build the entity query to load article nodes tagged with 'foobar'

```php
use Drupal\node\Entity\Node;

/**
 * Load article nodes tagged with a specific taxonomy term.
 *
 * @param int $term_id
 *   The taxonomy term ID.
 * @param int $limit
 *   Number of nodes to load.
 *
 * @return \Drupal\node\Entity\Node[]
 *   Array of node entities.
 */
function load_articles_by_tag(int $term_id, int $limit = 10): array {
  $query = \Drupal::entityQuery('node')
    ->condition('type', 'article')
    ->condition('status', 1)
    ->condition('field_tags', $term_id)
    ->range(0, $limit)
    ->sort('created', 'DESC');

  $nids = $query->execute();

  if (empty($nids)) {
    return [];
  }

  // Load nodes with entity load multiple for efficiency.
  return Node::loadMultiple($nids);
}
```

---

## Step 3: Render the nodes in teaser view mode with Bootstrap 5 styles

```php
use Drupal\Core\Render\RendererInterface;
use Drupal\Core\Render\Markup;

/**
 * Render a list of nodes with Bootstrap 5 styling.
 *
 * @param \Drupal\node\Entity\Node[] $nodes
 *   Array of node entities.
 *
 * @return array
 *   Render array.
 */
function render_article_teasers(array $nodes): array {
  $renderer = \Drupal::service('renderer');
  $view_builder = \Drupal::entityTypeManager()->getViewBuilder('node');

  $items = [];
  foreach ($nodes as $node) {
    $view = $view_builder->view($node, 'teaser');
    $items[] = [
      '#markup' => $renderer->render($view),
      '#wrapper_attributes' => ['class' => ['list-group-item']],
    ];
  }

  // Build a Bootstrap 5 list group.
  $render_array = [
    '#type' => 'container',
    '#attributes' => ['class' => ['list-group']],
    'items' => $items,
  ];

  return $render_array;
}
```

