use Symfony\Component\DependencyInjection\ContainerInterface;

class ArticleListController extends ControllerBase {

  public function teaserList() {
    $term_name = 'foobar';
    $vocabulary = 'tags';

    $term_id = get_term_id_by_name($term_name, $vocabulary);
    if (!$term_id) {
      return [
        '#markup' => $this->t('No articles found for the tag %tag.', ['%tag' => $term_name]),
      ];
    }

    $nodes = load_articles_by_tag($term_id, 10);
