events.subscribe('bar', onBar);

events.trigger('foo', { some: 'data' });
// Output: foo event triggered with { some: 'data' }

events.trigger(['foo', 'bar'], 123);
// Output:
// foo event triggered with 123
// bar event triggered with 123

events.unsubscribe('foo', onFoo);
events.trigger('foo', 'test'); // no output since unsubscribed
