// services/UserService.ts
import { APIRequestContext } from '@playwright/test';

interface CreateUserPayload {
  // define the shape of createPayload here
  [key: string]: any;
}

interface PermissionPayload {
  // define the shape of permissionPayload here
  [key: string]: any;
  id?: string;
}

interface UserCredentials {
  username: string;
  password: string;
}

export class UserService {
  private request: APIRequestContext;

  constructor(request: APIRequestContext) {
    this.request = request;
  }

  async createUser(createPayload: CreateUserPayload): Promise<string> {
    const res = await this.request.post('/users/v2/create', { data: createPayload });
    if (res.status() !== 201) {
      throw new Error(`Failed to create user, status: ${res.status()}`);
    }
    const json = await res.json();
    return json.id;
  }

  async updatePermissions(permissionPayload: PermissionPayload): Promise<UserCredentials> {
    const res = await this.request.post('/users/v2/permissions', { data: permissionPayload });
    if (res.status() !== 200) {
      throw new Error(`Failed to update permissions, status: ${res.status()}`);
    }
    const json = await res.json();
    return {
      username: json.username,
      password: json.password,
    };
  }

  async createAdminUser(createPayload: CreateUserPayload, permissionPayload: PermissionPayload): Promise<UserCredentials> {
    const userId = await this.createUser(createPayload);
    const updatedPayload = { ...permissionPayload, id: userId };
    const credentials = await this.updatePermissions(updatedPayload);
    return credentials;
  }
}
