        </tr>
        <tr v-if="error">
          <td colspan="3" class="error-row">{{ error }}</td>
        </tr>
        <tr v-if="!hasMore && !loading">
          <td colspan="3" class="end-row">No more data</td>
        </tr>
      </tbody>
    </table>
  </div>
