using namespace std;

const int MOD = 1e9 + 7;

struct SegmentTree {
    int n;
    vector<int> count;  // 记录覆盖次数
    vector<long long> length; // 记录覆盖长度

    vector<int> xs; // 离散化后的x坐标

    SegmentTree(const vector<int>& xs_) {
        xs = xs_;
        n = (int)xs.size() - 1;
        count.assign(n * 4, 0);
        length.assign(n * 4, 0);
    }

    void pushup(int node, int l, int r) {
        if (count[node] > 0) {
            length[node] = (long long)(xs[r+1] - xs[l]);
        } else if (l == r) {
            length[node] = 0;
        } else {
            length[node] = length[node*2] + length[node*2+1];
        }
    }

    void update(int node, int l, int r, int ul, int ur, int val) {
        if (ur < l || ul > r) return;
        if (ul <= l && r <= ur) {
            count[node] += val;
            pushup(node, l, r);
            return;
        }
        int mid = (l + r) / 2;
        update(node*2, l, mid, ul, ur, val);
        update(node*2+1, mid+1, r, ul, ur, val);
        pushup(node, l, r);
    }

    long long query() {
        return length[1];
    }
};

