```java
import java.util.ArrayList;
import java.util.List;

public class Staircase {

    public static void main(String[] args) {
        int n = 4; // 你可以修改n的值测试不同的台阶数
        List<List<Integer>> results = new ArrayList<>();
        List<Integer> path = new ArrayList<>();

        findWays(n, path, results);

        System.out.println("总共有 " + results.size() + " 种走法。");
        for (List<Integer> way : results) {
            System.out.println(way);
        }
    }

    /**
     * 递归查找所有走法
     * @param steps 剩余台阶数
     * @param path 当前路径（走法）
     * @param results 结果集合，存储所有走法
     */
    private static void findWays(int steps, List<Integer> path, List<List<Integer>> results) {
        if (steps == 0) {
            // 到达终点，保存当前路径
            results.add(new ArrayList<>(path));
            return;
        }
        if (steps < 0) {
            // 超过台阶数，返回
            return;
        }

        // 走1步
        path.add(1);
        findWays(steps - 1, path, results);
        path.remove(path.size() - 1);

        // 走2步
        path.add(2);
        findWays(steps - 2, path, results);
        path.remove(path.size() - 1);
    }
}
```

