```c
#include <stdio.h>

// Hàm Euclide mở rộng
// Trả về d = gcd(a,b), đồng thời tìm x,y sao cho ax + by = d
void extendedEuclid(int a, int b, int *d, int *x, int *y) {
    if (b == 0) {
        *d = a;
        *x = 1;
        *y = 0;
        return;
    }

    int X2 = 1, X1 = 0, Y2 = 0, Y1 = 1;
    int q, r;
    int x_temp, y_temp;

    while (b > 0) {
        q = a / b;
        r = a - q * b;

        x_temp = X2 - q * X1;
        y_temp = Y2 - q * Y1;

        a = b;
        b = r;

        X2 = X1;
        X1 = x_temp;

        Y2 = Y1;
        Y1 = y_temp;
    }

    *d = a;
    *x = X2;
    *y = Y2;
}

int main() {
    int a, b, d, x, y;
    printf("Nhap a va b: ");
    scanf("%d%d", &a, &b);

    extendedEuclid(a, b, &d, &x, &y);

    printf("Uoc chung lon nhat cua %d va %d la %d\n", a, b, d);
    printf("He so x va y thoa man %d*%d + %d*%d = %d\n", a, x, b, y, d);

    return 0;
}
```

**Giải thích:**

- Nếu b = 0, ta trả về d = a, x = 1, y = 0.
- Khởi tạo X2 = 1, X1 = 0, Y2 = 0, Y1 = 1.
- Trong vòng lặp while, ta tính thương q, số dư r, cập nhật các hệ số x, y theo công thức.
- Cuối cùng trả về d, x, y.

